class Ita {
    constructor(i) {
        Object.assign(this, ita_default, i), this.params = new URLSearchParams(window.location.search), this.elements = document.querySelectorAll(".ita .ita-menu[data-spid-remote]"), this.elements.length > 0 && this.start()

    }
    async start() {
        try {
            if (local) {
                let list = Array.isArray(this.idps) && this.idps.length ? this.idps : null;
                if (!list) {
                    const res = await fetch(this.localIdpsUrl);
                    list = res.ok ? await res.json() : [];
                }
                this.spid_populate(list)
            } else {
                const i = await fetch(this.url);
                i.ok && this.spid_populate(await i.json())
            }
        } catch (i) {
            console.log(i);
            const fallback = Array.isArray(this.idps) ? this.idps : [];
            this.spid_populate(fallback)
        }
    }
    spid_populate(i) {
        const a = i.sort(() => Math.random() - .5);
        for (var t = 0; t < this.elements.length; t++) {
            this.elements[t].innerHTML = this.addition;
            for (var e = 0; e < i.length; e++) this.add_idp_entry(i[e], this.elements[t])
        }
    }
    add_idp_entry(i, a) {
        let t = document.createElement("a");
        t.setAttribute("href", this.href(i, this.params));
        const logoHtml = (i.logo_uri && i.logo_uri.trim()) ? `<img src="${i.logo_uri}" alt="${i.organization_name}">` : `<span class="spid-idp-name">${i.organization_name}</span>`;
        t.innerHTML = logoHtml;
        a.prepend(t)
    }
};
